function solve(edges: number[][], online: boolean[], k: number): number {
    const n = online.length;
    const graph: Map<number, Map<number, number>> = new Map();

    // Build the graph
    for (const [u, v, cost] of edges) {
        if (!graph.has(u)) {
            graph.set(u, new Map());
        }
        graph.get(u)!.set(v, cost);
    }

    // Use Dijkstra's algorithm to find the maximum minimum edge cost
    // We use a priority queue to process nodes in order of maximum minimum edge cost
    // We also track the minimum edge cost to reach each node

    const maxMinCost = new Array(n).fill(-1);
    const pq = new MaxHeap((a, b) => b[0] - a[0]);

    // Start from node 0
    pq.push([0, 0, 0]); // [minEdgeCost, totalCost, node]
    maxMinCost[0] = 0;

    while (!pq.isEmpty()) {
        const [minEdge, totalCost, u] = pq.pop();

        // If we reached the destination node, return the minEdge
        if (u === n - 1) {
            return minEdge;
        }

        // Skip if we already found a better path to this node
        if (maxMinCost[u] !== -1 && maxMinCost[u] > minEdge) {
            continue;
        }

        // Explore neighbors
        if (graph.has(u)) {
            for (const [v, cost] of Array.from(graph.get(u)!.entries())) {
                // Skip if the node is offline
                if (!online[v]) continue;

                // Calculate the new total cost and new min edge
                const newTotalCost = totalCost + cost;
                const newMinEdge = Math.min(minEdge, cost);

                // If the new total cost is within k and we haven't found a better path to v
                if (newTotalCost <= k && maxMinCost[v] === -1 || newMinEdge > maxMinCost[v]) {
                    maxMinCost[v] = newMinEdge;
                    pq.push([newMinEdge, newTotalCost, v]);
                }
            }
        }
    }

    // If no valid path found
    return -1;
}

class MaxHeap {
    private heap: number[][];

    constructor(private comparator: (a: number[], b: number[]) => number) {
        this.heap = [];
    }

    push(value: number[]): void {
        this.heap.push(value);
        this.heap.sort(this.comparator);
    }

    pop(): number[] {
        return this.heap.shift()!;
    }

    isEmpty(): boolean {
        return this.heap.length === 0;
    }
}
